import {useEffect, useState} from 'react';

function Personas() {
    const [state, setState] = useState({list:[]});
    const backend="http://localhost:8080";
    useEffect(handleList, []);

    function handleList(){
        (async ()=>{
            const request = new Request(backend+'/personas', {method: 'GET', headers: { }});
            const response = await fetch(request);
            if (!response.ok) {alert("Error: "+response.status);return;}
            const list = await response.json();
            setState({...state, list: list});
        })();
    }

    return ( <List list={state.list} /> );
}

function List({list}){
    return (
        <>
            <style>{ `table, th, td { border: 1px solid red; border-collapse: collapse;margin-left: auto; margin-right: auto;} 
                    div.personas {background-color:#e6eeff; width:100%; min-height: 80vh; text-align: center; font-size:1.5em; }
                `}
            </style>
            <div className="personas">
                <table>
                    <thead>
                        <tr> <th>Cedula</th> <th>Nombre</th> <th>Sexo</th></tr>
                    </thead>
                    <tbody id="listado">
                        {list.map((p) => (
                            <tr key={p.cedula}><td>{p.cedula}</td><td>{p.nombre}</td><td>{p.sexo}</td></tr>
                        ))}
                    </tbody>
                </table>
        </div>
        </>
    );
}

export default Personas;
